-- Migration: 00000000100126_earning_strategies_color_reveal.sql
-- Build M Phase 1 — Earning Strategy Foundation + Color Reveal Schema
--
-- Creates:
--   1. task_segments table
--   2. coloring_reveal_library table (32 rows seeded from zones.json)
--   3. member_coloring_reveals table
--   4. New columns on member_sticker_book_state (earning modes)
--   5. New column on tasks (task_segment_id)
--   6. Refactored roll_creature_for_completion RPC (strategy branching)
--   7. Helper RPCs: check_segment_completion, check_day_completion, advance_coloring_reveal
--   8. Feature keys
--
-- Idempotent: ADD COLUMN IF NOT EXISTS, CREATE TABLE IF NOT EXISTS, ON CONFLICT DO NOTHING

-- ═══════════════════════════════════════════════════════════════════════
-- 1. task_segments
-- ═══════════════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS public.task_segments (
  id                          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  family_id                   UUID NOT NULL REFERENCES public.families(id) ON DELETE CASCADE,
  family_member_id            UUID NOT NULL REFERENCES public.family_members(id) ON DELETE CASCADE,
  segment_name                TEXT NOT NULL,
  icon_key                    TEXT,
  sort_order                  INTEGER NOT NULL DEFAULT 0,
  day_filter                  INTEGER[],
  creature_earning_enabled    BOOLEAN NOT NULL DEFAULT true,
  segment_complete_celebration BOOLEAN NOT NULL DEFAULT true,
  randomizer_reveal_style     TEXT NOT NULL DEFAULT 'mystery_tap'
                                CHECK (randomizer_reveal_style IN ('show_upfront', 'mystery_tap')),
  theme_override_id           UUID REFERENCES public.gamification_themes(id),
  is_active                   BOOLEAN NOT NULL DEFAULT true,
  created_at                  TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at                  TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.task_segments ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "task_segments_family_read" ON public.task_segments;
CREATE POLICY "task_segments_family_read"
  ON public.task_segments FOR SELECT
  USING (
    family_id IN (
      SELECT family_id FROM public.family_members WHERE user_id = auth.uid()
    )
  );

DROP POLICY IF EXISTS "task_segments_mom_write" ON public.task_segments;
CREATE POLICY "task_segments_mom_write"
  ON public.task_segments FOR ALL
  USING (
    family_id IN (
      SELECT family_id FROM public.family_members
      WHERE user_id = auth.uid() AND role = 'primary_parent'
    )
  )
  WITH CHECK (
    family_id IN (
      SELECT family_id FROM public.family_members
      WHERE user_id = auth.uid() AND role = 'primary_parent'
    )
  );

CREATE INDEX IF NOT EXISTS idx_task_segments_member_active
  ON public.task_segments(family_member_id, is_active, sort_order);

DROP TRIGGER IF EXISTS trg_task_segments_updated_at ON public.task_segments;
CREATE TRIGGER trg_task_segments_updated_at
  BEFORE UPDATE ON public.task_segments
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- ═══════════════════════════════════════════════════════════════════════
-- 2. tasks.task_segment_id
-- ═══════════════════════════════════════════════════════════════════════

ALTER TABLE public.tasks ADD COLUMN IF NOT EXISTS
  task_segment_id UUID REFERENCES public.task_segments(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_tasks_segment
  ON public.tasks(task_segment_id)
  WHERE task_segment_id IS NOT NULL;

-- ═══════════════════════════════════════════════════════════════════════
-- 3. coloring_reveal_library (platform-level, theme-scoped)
-- ═══════════════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS public.coloring_reveal_library (
  id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  theme_id            UUID NOT NULL REFERENCES public.gamification_themes(id) ON DELETE CASCADE,
  slug                TEXT NOT NULL UNIQUE,
  display_name        TEXT NOT NULL,
  subject_category    TEXT NOT NULL CHECK (subject_category IN ('animal', 'scene')),
  color_zones         JSONB NOT NULL,
  reveal_sequences    JSONB NOT NULL,
  zone_count          INTEGER NOT NULL DEFAULT 50,
  sort_order          INTEGER NOT NULL DEFAULT 0,
  is_active           BOOLEAN NOT NULL DEFAULT true,
  created_at          TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.coloring_reveal_library ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "coloring_reveal_library_public_read" ON public.coloring_reveal_library;
CREATE POLICY "coloring_reveal_library_public_read"
  ON public.coloring_reveal_library FOR SELECT
  USING (auth.role() = 'authenticated');

CREATE INDEX IF NOT EXISTS idx_coloring_reveal_library_theme_active
  ON public.coloring_reveal_library(theme_id, is_active, sort_order);

-- ═══════════════════════════════════════════════════════════════════════
-- 4. member_coloring_reveals (per-member active reveal progress)
-- ═══════════════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS public.member_coloring_reveals (
  id                          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  family_id                   UUID NOT NULL REFERENCES public.families(id) ON DELETE CASCADE,
  family_member_id            UUID NOT NULL REFERENCES public.family_members(id) ON DELETE CASCADE,
  coloring_image_id           UUID NOT NULL REFERENCES public.coloring_reveal_library(id) ON DELETE CASCADE,
  reveal_step_count           INTEGER NOT NULL CHECK (reveal_step_count IN (5, 10, 15, 20, 30, 50)),
  current_step                INTEGER NOT NULL DEFAULT 0,
  revealed_zone_ids           INTEGER[] NOT NULL DEFAULT '{}',
  earning_mode                TEXT NOT NULL DEFAULT 'every_n_completions'
                                CHECK (earning_mode IN (
                                  'segment_complete', 'every_n_completions',
                                  'complete_the_day', 'random_per_task'
                                )),
  earning_threshold           INTEGER NOT NULL DEFAULT 5,
  earning_counter             INTEGER NOT NULL DEFAULT 0,
  earning_segment_ids         UUID[] DEFAULT '{}',
  earning_tracker_widget_id   UUID,
  earning_tracker_threshold   INTEGER,
  lineart_preference          TEXT NOT NULL DEFAULT 'medium'
                                CHECK (lineart_preference IN ('simple', 'medium', 'complex')),
  is_complete                 BOOLEAN NOT NULL DEFAULT false,
  completed_at                TIMESTAMPTZ,
  printed_at                  TIMESTAMPTZ,
  is_active                   BOOLEAN NOT NULL DEFAULT true,
  created_at                  TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at                  TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.member_coloring_reveals ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "member_coloring_reveals_family_read" ON public.member_coloring_reveals;
CREATE POLICY "member_coloring_reveals_family_read"
  ON public.member_coloring_reveals FOR SELECT
  USING (
    family_id IN (
      SELECT family_id FROM public.family_members WHERE user_id = auth.uid()
    )
  );

DROP POLICY IF EXISTS "member_coloring_reveals_mom_write" ON public.member_coloring_reveals;
CREATE POLICY "member_coloring_reveals_mom_write"
  ON public.member_coloring_reveals FOR ALL
  USING (
    family_id IN (
      SELECT family_id FROM public.family_members
      WHERE user_id = auth.uid() AND role = 'primary_parent'
    )
  )
  WITH CHECK (
    family_id IN (
      SELECT family_id FROM public.family_members
      WHERE user_id = auth.uid() AND role = 'primary_parent'
    )
  );

CREATE INDEX IF NOT EXISTS idx_member_coloring_reveals_member_active
  ON public.member_coloring_reveals(family_member_id, is_active);

CREATE INDEX IF NOT EXISTS idx_member_coloring_reveals_member_complete
  ON public.member_coloring_reveals(family_member_id, is_complete);

DROP TRIGGER IF EXISTS trg_member_coloring_reveals_updated_at ON public.member_coloring_reveals;
CREATE TRIGGER trg_member_coloring_reveals_updated_at
  BEFORE UPDATE ON public.member_coloring_reveals
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- ═══════════════════════════════════════════════════════════════════════
-- 5. member_sticker_book_state — earning mode columns
-- ═══════════════════════════════════════════════════════════════════════

DO $$
BEGIN
  -- creature_earning_mode
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'creature_earning_mode'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN creature_earning_mode TEXT NOT NULL DEFAULT 'random_per_task'
        CHECK (creature_earning_mode IN ('segment_complete','every_n_completions','complete_the_day','random_per_task'));
  END IF;

  -- creature_earning_threshold
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'creature_earning_threshold'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN creature_earning_threshold INTEGER NOT NULL DEFAULT 3;
  END IF;

  -- creature_earning_counter
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'creature_earning_counter'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN creature_earning_counter INTEGER NOT NULL DEFAULT 0;
  END IF;

  -- creature_earning_counter_resets
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'creature_earning_counter_resets'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN creature_earning_counter_resets BOOLEAN NOT NULL DEFAULT true;
  END IF;

  -- creature_earning_segment_ids
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'creature_earning_segment_ids'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN creature_earning_segment_ids UUID[] DEFAULT '{}';
  END IF;

  -- page_earning_mode
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'page_earning_mode'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN page_earning_mode TEXT NOT NULL DEFAULT 'every_n_creatures'
        CHECK (page_earning_mode IN ('tracker_goal','every_n_creatures','every_n_completions'));
  END IF;

  -- page_earning_completion_threshold
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'page_earning_completion_threshold'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN page_earning_completion_threshold INTEGER NOT NULL DEFAULT 20;
  END IF;

  -- page_earning_completion_counter
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'page_earning_completion_counter'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN page_earning_completion_counter INTEGER NOT NULL DEFAULT 0;
  END IF;

  -- page_earning_tracker_widget_id
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'page_earning_tracker_widget_id'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN page_earning_tracker_widget_id UUID;
  END IF;

  -- page_earning_tracker_threshold
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'page_earning_tracker_threshold'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN page_earning_tracker_threshold INTEGER NOT NULL DEFAULT 5;
  END IF;

  -- randomizer_reveal_style
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'member_sticker_book_state'
      AND column_name = 'randomizer_reveal_style'
  ) THEN
    ALTER TABLE public.member_sticker_book_state
      ADD COLUMN randomizer_reveal_style TEXT NOT NULL DEFAULT 'mystery_tap'
        CHECK (randomizer_reveal_style IN ('show_upfront','mystery_tap'));
  END IF;
END;
$$;

