  ('gamification_earning_modes', 'Gamification Earning Modes',  'Configurable creature and page earning strategies',        'PRD-24'),
  ('coloring_reveal_basic',      'Coloring Reveal Basic',       'Color reveal reward images — basic functionality',         'PRD-24'),
  ('coloring_reveal_print',      'Coloring Reveal Print',       'Print line art from completed coloring reveals',           'PRD-24')
