INSERT INTO public.feature_access_v2 (feature_key, role_group, minimum_tier_id, is_enabled)
SELECT fk.feature_key, rg.role_group, NULL, true
FROM (VALUES
  ('task_segments'),
  ('gamification_earning_modes'),
  ('coloring_reveal_basic'),
  ('coloring_reveal_print')
) AS fk(feature_key)
CROSS JOIN (VALUES
  ('mom'), ('dad_adults'), ('special_adults'),
  ('independent_teens'), ('guided_kids'), ('play_kids')
) AS rg(role_group)
ON CONFLICT DO NOTHING;

