,{"id":24,"hex":"#CDDBE1","name":"Pale icy blue snow on trees","pct":1.82},{"id":25,"hex":"#112222","name":"Very dark green tree shadows","pct":1.76},{"id":26,"hex":"#1D2F2F","name":"Dark teal shadows on pine trees","pct":1.76},{"id":27,"hex":"#484C4E","name":"Muted dark gray shading on tree trunks","pct":1.67},{"id":28,"hex":"#A5A296","name":"Light brown tree trunk highlights","pct":1.64},{"id":29,"hex":"#263E3D","name":"Dark teal-green pine tree shadows","pct":1.48},{"id":30,"hex":"#979587","name":"Muted olive green foliage shading","pct":1.46},{"id":31,"hex":"#395456","name":"Deep forest green pine tree foliage","pct":1.44},{"id":32,"hex":"#76898C","name":"Muted blue-gray shading on snowy trees","pct":1.37},{"id":33,"hex":"#476264","name":"Dark teal pine tree foliage","pct":1.34},{"id":34,"hex":"#667B7D","name":"Muted blue-green pine tree shading","pct":1.24},{"id":35,"hex":"#081314","name":"Very dark black shadows on husky''s eyes","pct":1.21},{"id":36,"hex":"#576E6F","name":"Muted blue-green pine tree shadows","pct":1.21},{"id":37,"hex":"#333636","name":"Dark gray shadow details on husky fur","pct":0.97},{"id":38,"hex":"#7A7461","name":"Muted brown tree trunk shadows","pct":0.96},{"id":39,"hex":"#88AAB7","name":"Light blue highlights on snowy trees","pct":0.93},{"id":40,"hex":"#888471","name":"Muted brown-gray shading on tree trunks","pct":0.92},{"id":41,"hex":"#99BCC8","name":"Soft blue snowflake highlights","pct":0.87},{"id":42,"hex":"#6A6351","name":"Dark brown tree trunk shadows","pct":0.86},{"id":43,"hex":"#7799A6","name":"Muted blue-gray shading on trees","pct":0.86},{"id":44,"hex":"#B0CDD7","name":"Pale blue snow and icy highlights","pct":0.8},{"id":45,"hex":"#444233","name":"Dark olive brown tree trunk shadows","pct":0.75},{"id":46,"hex":"#565440","name":"Muted olive green foliage shadows","pct":0.72},{"id":47,"hex":"#5F8696","name":"Muted blue-gray pine tree shading","pct":0.69},{"id":48,"hex":"#1C1410","name":"Very dark brown shadow details on tree tr