-- Verification notices
-- ═══════════════════════════════════════════════════════════════════════

DO $$
BEGIN
  RAISE NOTICE 'task_segments: %', (SELECT count(*) FROM public.task_segments);
  RAISE NOTICE 'coloring_reveal_library: % rows', (SELECT count(*) FROM public.coloring_reveal_library);
  RAISE NOTICE 'member_coloring_reveals: % rows', (SELECT count(*) FROM public.member_coloring_reveals);
  RAISE NOTICE 'creature_earning_mode column: %',
    EXISTS(SELECT 1 FROM information_schema.columns WHERE table_name='member_sticker_book_state' AND column_name='creature_earning_mode');
  RAISE NOTICE 'task_segment_id column: %',
    EXISTS(SELECT 1 FROM information_schema.columns WHERE table_name='tasks' AND column_name='task_segment_id');
END;
$$;
